/**
 * @summary Upload document for submission
 */
export const getUploadDocumentUrl = (id: number) => {
  return `/api/submissions/${id}/upload`;
};

export const uploadDocument = async (
  id: number,
  uploadDocumentBody: UploadDocumentBody,
  options?: RequestInit,
): Promise<Document> => {
  const formData = new FormData();
  if (uploadDocumentBody.file !== undefined) {
    formData.append(`file`, uploadDocumentBody.file);
  }
  if (uploadDocumentBody.docType !== undefined) {
    formData.append(`docType`, uploadDocumentBody.docType);
  }

  return customFetch<Document>(getUploadDocumentUrl(id), {
    ...options,
    method: "POST",
    body: formData,
  });
};

